// Split the tech items into 4 thematic rows for infinite marquees
const row1 = techInventory.filter(
  (item) => item.category === "Languages & Frameworks",
);
const row2 = techInventory.filter(
  (item) => item.category === "State & Libraries",
);
const row3 = techInventory.filter((item) => item.category === "UI & Styling");
const row4 = techInventory.filter(
  (item) => item.category === "Backend & DevTools",
);

function MarqueeRow({
  items,
  direction,
  speed = 35,
}: {
  items: TechItem[];
  direction: "left" | "right";
  speed?: number;
}) {
  const duplicatedItems = [...items, ...items, ...items, ...items];
  const { theme } = useTheme();
  const isDark = theme === "dark";

  return (
    <div className="relative flex overflow-hidden py-3 w-full marquee-container">
      <div
        className={
          direction === "left"
            ? "animate-marquee-left"
            : "animate-marquee-right"
        }
        style={{ "--duration": `${speed}s` } as React.CSSProperties}
      >
        {duplicatedItems.map((item, idx) => (
          <motion.div
            key={`${item.name}-${idx}`}
            whileHover={{
              scale: 1.05,
              y: -4,
              boxShadow: isDark
                ? `0 15px 30px -10px ${item.color}35, 0 5px 15px -8px ${item.color}15`
                : `0 15px 30px -10px ${item.color}20, 0 5px 15px -8px ${item.color}08`,
              borderColor: isDark ? `${item.color}40` : `${item.color}50`,
            }}
            transition={{ type: "spring", stiffness: 400, damping: 25 }}
            className="flex items-center gap-3 mx-4 px-5 py-3 rounded-2xl border border-border dark:border-white/5 bg-glass dark:bg-white/[0.02] light:bg-white hover:border-accent/30 dark:hover:border-accent/30 transition-all duration-300 select-none group cursor-default shadow-sm"
          >
            <div
              className={`flex items-center justify-center transition-all duration-300 group-hover:scale-105 ${isDark ? "" : "opacity-85"}`}
            >
              {item.logo}
            </div>
            <span
              className={`text-xs font-semibold tracking-wide transition-colors duration-300 whitespace-nowrap ${isDark ? "text-foreground/80 group-hover:text-foreground" : "text-slate-600 group-hover:text-slate-900"}`}
              style={isDark ? { color: `${item.color}bb` } : undefined}
            >
              {item.name}
            </span>
          </motion.div>
        ))}
      </div>
    </div>
  );
}

export function TechArsenalSection() {
  const { t } = useTranslation();
  return (
    <section
      id="tech"
      className="relative section-padding overflow-hidden"
      aria-label="Tech Arsenal"
    >
      <div className="absolute inset-0 bg-gradient-to-b from-transparent via-accent/3 to-transparent pointer-events-none" />

      <div className="container-wide relative z-10">
        <SectionHeading
          label={t('tech.label')}
          title={t('tech.title')}
          description={t('tech.description')}
          align="center"
        />

        <div className="flex flex-col gap-4 mt-12 max-w-5xl mx-auto" dir="ltr">
          {/* Row 1 -> Left (Languages & Core Web) */}
          <MarqueeRow items={row1} direction="left" speed={32} />

          {/* Row 2 -> Right (State & Core Libraries) */}
          <MarqueeRow items={row2} direction="right" speed={28} />

          {/* Row 3 -> Left (UI & Styling) */}
          <MarqueeRow items={row3} direction="left" speed={30} />

          {/* Row 4 -> Right (Backend, DevTools & Workflow) */}
          <MarqueeRow items={row4} direction="right" speed={38} />
        </div>
      </div>
    </section>
  );
}
